// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.Method;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class PackedMemoContractTest {

	@Test
	void baseAndOverlayInsertionAreIdempotentWithPermanentGroups() {
		PackedQuery query = query();
		PackedMemo memo = memo(query);
		int rootExpressionId = query.rootRelId();
		int rootGroupId = memo.logicalGroupId(rootExpressionId);
		int[] children = { query.relChild(rootExpressionId, 0), query.relChild(rootExpressionId, 1) };
		int initialExpressionCount = memo.logicalExpressionCount();
		int initialGroupCount = memo.groupCount();

		int repeated = memo.addLogicalAlternative(rootGroupId, PackedRelOp.JOIN, 0, 0, 0, children, 0, 2);
		assertEquals(rootExpressionId, repeated);
		assertEquals(initialExpressionCount, memo.logicalExpressionCount());
		assertEquals(initialGroupCount, memo.groupCount());

		assertThrows(PackedMemoInvariantException.class,
				() -> memo.addLogicalAlternative(children[0], PackedRelOp.JOIN, 0, 0, 0, children, 0, 2));

		int helper = memo.addCanonicalLogical(99, 17, 2, 3, new int[] { rootGroupId }, 0, 1);
		int helperGroup = memo.logicalGroupId(helper);
		assertEquals(helper, memo.addCanonicalLogical(99, 17, 2, 3, new int[] { rootGroupId }, 0, 1));
		assertEquals(initialExpressionCount + 1, memo.logicalExpressionCount());
		assertEquals(initialGroupCount + 1, memo.groupCount());
		assertEquals(initialGroupCount + 1, helperGroup);
	}

	@Test
	void logicalPhysicalAndWinnerIdentitiesRemainSeparate() {
		PackedQuery query = query();
		PackedMemo memo = memo(query);
		int rootExpressionId = query.rootRelId();
		int rootGroupId = memo.logicalGroupId(rootExpressionId);
		int[] children = { query.relChild(rootExpressionId, 0), query.relChild(rootExpressionId, 1) };
		int anyPropertyId = memo.anyPropertyId();
		int accessPathPropertyId = memo.internProperty(0, 0, 77, 0, 0, 0, 0, 0, 0, 0, 0, 0);

		int physical = memo.addPhysicalAlternative(rootGroupId, 200, 31, anyPropertyId, 5, children, 0, 2);
		assertEquals(physical,
				memo.addPhysicalAlternative(rootGroupId, 200, 31, anyPropertyId, 5, children, 0, 2));
		assertNotEquals(physical,
				memo.addPhysicalAlternative(rootGroupId, 200, 31, accessPathPropertyId, 5, children, 0, 2));
		assertNotEquals(physical,
				memo.addPhysicalAlternative(rootGroupId, 200, 31, anyPropertyId, 6, children, 0, 2));
		assertEquals(3, memo.physicalExpressionCount());

		int[] noChildWinners = new int[0];
		int anyWinner = memo.offerWinner(rootGroupId, anyPropertyId, 0, 0, 0, physical, 2.0d, 20.0d,
				20.0d, noChildWinners, 0, 0);
		int accessPathWinner = memo.offerWinner(rootGroupId, accessPathPropertyId, 0, 0, 0, physical, 2.0d,
				20.0d, 20.0d, noChildWinners, 0, 0);
		assertNotEquals(anyWinner, accessPathWinner);
		assertEquals(anyWinner, memo.offerWinner(rootGroupId, anyPropertyId, 0, 0, 0, physical, 1.0d, 10.0d,
				10.0d, noChildWinners, 0, 0));
		assertEquals(10.0d, memo.winnerTotalCost(anyWinner));
		assertEquals(2, memo.winnerCount());
		assertEquals(physical, memo.winnerPhysicalExpressionId(anyWinner));
	}

	@Test
	void memoSurfaceHasNoGroupMergeOrRenameOperation() {
		for (Method method : PackedMemo.class.getDeclaredMethods()) {
			String name = method.getName().toLowerCase();
			assertFalse(name.contains("merge") || name.contains("alias") || name.contains("rename")
					|| name.contains("rehash"), name);
		}
	}

	private static PackedMemo memo(PackedQuery query) {
		return new PackedMemo(query, 130, 16, 16, 16, 16, 32);
	}

	private static PackedQuery query() {
		SimpleValueFactory valueFactory = SimpleValueFactory.getInstance();
		StatementPattern left = new StatementPattern(Var.of("person"),
				Var.of("namePredicate", valueFactory.createIRI("urn:name")), Var.of("name"));
		StatementPattern right = new StatementPattern(Var.of("person"),
				Var.of("agePredicate", valueFactory.createIRI("urn:age")), Var.of("age"));
		return PackedQueryCodec.encode(new Join(left, right));
	}
}
